prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?startName ?endName WHERE {
  ?startNode bbo:name "genehmigten uund unterzeichneten Urlaubsantrag weiterleiten" .
  ?endNode bbo:name "ausgefüllten und unterschriebenen Urlaubsantrag senden" .

  # Check if there is a path from startNode to endNode
  ?startNode ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?endNode .

  OPTIONAL { ?startNode bbo:name ?startName . }
  OPTIONAL { ?endNode bbo:name ?endName . }
}
